// MetricsBuilder provides an interface for scrapers to report metrics while taking care of all the transformations
// required to produce metric representation defined in metadata and user config.
type MetricsBuilder struct {
	config                                 MetricsBuilderConfig // config of the metrics builder.
	startTime                              pcommon.Timestamp    // start time that will be applied to all recorded data points.
	metricsCapacity                        int                  // maximum observed number of metrics per resource.
	metricsBuffer                          pmetric.Metrics      // accumulates metrics data before emitting.
	buildInfo                              component.BuildInfo  // contains version information.
	metricChromiumPageDocumentCount        metricChromiumPageDocumentCount
	metricChromiumPageDomNodeCount         metricChromiumPageDomNodeCount
	metricChromiumPageFrameCount           metricChromiumPageFrameCount
	metricChromiumPageJsEventListenerCount metricChromiumPageJsEventListenerCount
	metricChromiumPageJsHeapTotalSize      metricChromiumPageJsHeapTotalSize
	metricChromiumPageJsHeapUsedSize       metricChromiumPageJsHeapUsedSize
	metricChromiumPageLayoutCount          metricChromiumPageLayoutCount
	metricChromiumPageLayoutDuration       metricChromiumPageLayoutDuration
	metricChromiumPageRecalcStyleCount     metricChromiumPageRecalcStyleCount
	metricChromiumPageRecalcStyleDuration  metricChromiumPageRecalcStyleDuration
	metricChromiumPageScriptDuration       metricChromiumPageScriptDuration
	metricChromiumPageTaskDuration         metricChromiumPageTaskDuration
	metricChromiumTargetsCount             metricChromiumTargetsCount
}

// MetricBuilderOption applies changes to default metrics builder.
type MetricBuilderOption interface {
	apply(*MetricsBuilder)
}

type metricBuilderOptionFunc func(mb *MetricsBuilder)

func (mbof metricBuilderOptionFunc) apply(mb *MetricsBuilder) {
	mbof(mb)
}

// WithStartTime sets startTime on the metrics builder.
func WithStartTime(startTime pcommon.Timestamp) MetricBuilderOption {
	return metricBuilderOptionFunc(func(mb *MetricsBuilder) {
		mb.startTime = startTime
	})
}
func NewMetricsBuilder(mbc MetricsBuilderConfig, settings receiver.Settings, options ...MetricBuilderOption) *MetricsBuilder {
	mb := &MetricsBuilder{
		config:                                 mbc,
		startTime:                              pcommon.NewTimestampFromTime(time.Now()),
		metricsBuffer:                          pmetric.NewMetrics(),
		buildInfo:                              settings.BuildInfo,
		metricChromiumPageDocumentCount:        newMetricChromiumPageDocumentCount(mbc.Metrics.ChromiumPageDocumentCount),
		metricChromiumPageDomNodeCount:         newMetricChromiumPageDomNodeCount(mbc.Metrics.ChromiumPageDomNodeCount),
		metricChromiumPageFrameCount:           newMetricChromiumPageFrameCount(mbc.Metrics.ChromiumPageFrameCount),
		metricChromiumPageJsEventListenerCount: newMetricChromiumPageJsEventListenerCount(mbc.Metrics.ChromiumPageJsEventListenerCount),
		metricChromiumPageJsHeapTotalSize:      newMetricChromiumPageJsHeapTotalSize(mbc.Metrics.ChromiumPageJsHeapTotalSize),
		metricChromiumPageJsHeapUsedSize:       newMetricChromiumPageJsHeapUsedSize(mbc.Metrics.ChromiumPageJsHeapUsedSize),
		metricChromiumPageLayoutCount:          newMetricChromiumPageLayoutCount(mbc.Metrics.ChromiumPageLayoutCount),
		metricChromiumPageLayoutDuration:       newMetricChromiumPageLayoutDuration(mbc.Metrics.ChromiumPageLayoutDuration),
		metricChromiumPageRecalcStyleCount:     newMetricChromiumPageRecalcStyleCount(mbc.Metrics.ChromiumPageRecalcStyleCount),
		metricChromiumPageRecalcStyleDuration:  newMetricChromiumPageRecalcStyleDuration(mbc.Metrics.ChromiumPageRecalcStyleDuration),
		metricChromiumPageScriptDuration:       newMetricChromiumPageScriptDuration(mbc.Metrics.ChromiumPageScriptDuration),
		metricChromiumPageTaskDuration:         newMetricChromiumPageTaskDuration(mbc.Metrics.ChromiumPageTaskDuration),
		metricChromiumTargetsCount:             newMetricChromiumTargetsCount(mbc.Metrics.ChromiumTargetsCount),
	}

	for _, op := range options {
		op.apply(mb)
	}
	return mb
}

// updateCapacity updates max length of metrics and resource attributes that will be used for the slice capacity.
func (mb *MetricsBuilder) updateCapacity(rm pmetric.ResourceMetrics) {
	if mb.metricsCapacity < rm.ScopeMetrics().At(0).Metrics().Len() {
		mb.metricsCapacity = rm.ScopeMetrics().At(0).Metrics().Len()
	}
}

// ResourceMetricsOption applies changes to provided resource metrics.
type ResourceMetricsOption interface {
	apply(pmetric.ResourceMetrics)
}

type resourceMetricsOptionFunc func(pmetric.ResourceMetrics)

func (rmof resourceMetricsOptionFunc) apply(rm pmetric.ResourceMetrics) {
	rmof(rm)
}

// WithResource sets the provided resource on the emitted ResourceMetrics.
// It's recommended to use ResourceBuilder to create the resource.
func WithResource(res pcommon.Resource) ResourceMetricsOption {
	return resourceMetricsOptionFunc(func(rm pmetric.ResourceMetrics) {
		res.CopyTo(rm.Resource())
	})
}

// WithStartTimeOverride overrides start time for all the resource metrics data points.
// This option should be only used if different start time has to be set on metrics coming from different resources.
func WithStartTimeOverride(start pcommon.Timestamp) ResourceMetricsOption {
	return resourceMetricsOptionFunc(func(rm pmetric.ResourceMetrics) {
		var dps pmetric.NumberDataPointSlice
		metrics := rm.ScopeMetrics().At(0).Metrics()
		for i := 0; i < metrics.Len(); i++ {
			switch metrics.At(i).Type() {
			case pmetric.MetricTypeGauge:
				dps = metrics.At(i).Gauge().DataPoints()
			case pmetric.MetricTypeSum:
				dps = metrics.At(i).Sum().DataPoints()
			}
			for j := 0; j < dps.Len(); j++ {
				dps.At(j).SetStartTimestamp(start)
			}
		}
	})
}

// EmitForResource saves all the generated metrics under a new resource and updates the internal state to be ready for
// recording another set of data points as part of another resource. This function can be helpful when one scraper
// needs to emit metrics from several resources. Otherwise calling this function is not required,
// just `Emit` function can be called instead.
// Resource attributes should be provided as ResourceMetricsOption arguments.
func (mb *MetricsBuilder) EmitForResource(options ...ResourceMetricsOption) {
	rm := pmetric.NewResourceMetrics()
	ils := rm.ScopeMetrics().AppendEmpty()
	ils.Scope().SetName(ScopeName)
	ils.Scope().SetVersion(mb.buildInfo.Version)
	ils.Metrics().EnsureCapacity(mb.metricsCapacity)
	mb.metricChromiumPageDocumentCount.emit(ils.Metrics())
	mb.metricChromiumPageDomNodeCount.emit(ils.Metrics())
	mb.metricChromiumPageFrameCount.emit(ils.Metrics())
	mb.metricChromiumPageJsEventListenerCount.emit(ils.Metrics())
	mb.metricChromiumPageJsHeapTotalSize.emit(ils.Metrics())
	mb.metricChromiumPageJsHeapUsedSize.emit(ils.Metrics())
	mb.metricChromiumPageLayoutCount.emit(ils.Metrics())
	mb.metricChromiumPageLayoutDuration.emit(ils.Metrics())
	mb.metricChromiumPageRecalcStyleCount.emit(ils.Metrics())
	mb.metricChromiumPageRecalcStyleDuration.emit(ils.Metrics())
	mb.metricChromiumPageScriptDuration.emit(ils.Metrics())
	mb.metricChromiumPageTaskDuration.emit(ils.Metrics())
	mb.metricChromiumTargetsCount.emit(ils.Metrics())

	for _, op := range options {
		op.apply(rm)
	}

	if ils.Metrics().Len() > 0 {
		mb.updateCapacity(rm)
		rm.MoveTo(mb.metricsBuffer.ResourceMetrics().AppendEmpty())
	}
}

// Emit returns all the metrics accumulated by the metrics builder and updates the internal state to be ready for
// recording another set of metrics. This function will be responsible for applying all the transformations required to
// produce metric representation defined in metadata and user config, e.g. delta or cumulative.
func (mb *MetricsBuilder) Emit(options ...ResourceMetricsOption) pmetric.Metrics {
	mb.EmitForResource(options...)
	metrics := mb.metricsBuffer
	mb.metricsBuffer = pmetric.NewMetrics()
	return metrics
}

// RecordChromiumPageDocumentCountDataPoint adds a data point to chromium.page.document.count metric.
